	r := newLandTestRepoWithOrigin(t)
	ops := RealLandingGitOps{}

	// Side-clone edits the SAME file (feature.txt) on origin so the auto-merge
	// against our worker's edits will conflict.
	sideDir, err := os.MkdirTemp("", "land-side-*")
	if err != nil {
		t.Fatal(err)
	}
	defer os.RemoveAll(sideDir)
	runCmd := func(dir string, args ...string) {
		c := exec.Command("git", append([]string{"-C", dir}, args...)...)
		out, cerr := c.CombinedOutput()
		if cerr != nil {
			t.Fatalf("git %s: %s: %v", strings.Join(args, " "), string(out), cerr)
		}
	}
	runCmd("", "clone", r.origin, sideDir)
	runCmd(sideDir, "config", "user.name", "Side")
	runCmd(sideDir, "config", "user.email", "side@test.local")
	if err := os.WriteFile(filepath.Join(sideDir, "feature.txt"), []byte("origin-version\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	runCmd(sideDir, "add", "-A")
	runCmd(sideDir, "commit", "-m", "remote: conflict")
	runCmd(sideDir, "push", "origin", "main")

	// Worker edits the same file with conflicting content.
	workerSHA := r.commitOn(r.baseSHA, "feature.txt", "worker-version\n", "feat: worker")

	req := LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-land-pushconflict",
		AttemptID:    "20260429T000002-pc",
		TargetBranch: "main",
	}
	land, err := Land(r.dir, req, ops)
	if err != nil {
		t.Fatalf("Land: %v", err)
	}
	if land.Status != "landed" {
		t.Fatalf("expected status=landed (local) even when push auto-recovery conflicts, got %q", land.Status)
	}
	if !land.PushConflict {
		t.Errorf("expected PushConflict=true when auto-merge conflicts, got false (PushFailed=%v PushError=%q)", land.PushFailed, land.PushError)
	}
	if land.PushFailed {
		t.Errorf("expected PushFailed=false (PushConflict is the more specific signal), got true")
	}
	if land.PushRecovered {
		t.Errorf("expected PushRecovered=false on conflict, got true")
	}
	if land.PushError == "" {
		t.Errorf("expected non-empty PushError describing the conflict, got empty")
	}
	// ApplyLandResultToExecuteBeadResult must surface the conflict marker so
	// the loop classifies the report as push_conflict, not push_failed.
	res := &ExecuteBeadResult{ExitCode: 0, BaseRev: r.baseSHA, ResultRev: workerSHA, BeadID: req.BeadID, AttemptID: req.AttemptID}
	ApplyLandResultToExecuteBeadResult(res, land)
	if !strings.HasPrefix(res.Reason, PushConflictReasonPrefix) {
		t.Errorf("expected res.Reason to start with PushConflictReasonPrefix, got %q", res.Reason)
	}
	if res.Status != ExecuteBeadStatusPushConflict {
		t.Errorf("expected res.Status = push_conflict, got %q", res.Status)
	}
}

// Deterministic test clock helper — avoids unused time import when no test
// overrides NowFunc.
var _ = time.Now

// TestExecuteBeadWorkerPushFailedCooldownCappedAt24h pins AC #2 + #7 of
// ddx-a458af7c: push_failed (and every other loop-set cooldown) caps at
// MaxLoopCooldown (24h). Year-scale parks are an operator decision via
// `ddx bead update --set execute-loop-retry-after=...`, never an automatic
// loop output.
func TestExecuteBeadWorkerPushFailedCooldownCappedAt24h(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusPushFailed,
				Detail:    PushFailedReasonPrefix + " remote rejected",
				SessionID: "sess-cap",
				BaseRev:   "aaaa",
				ResultRev: "bbbb",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	startedAt := time.Now().UTC()
	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)

	got, err := store.Get(first.ID)
	require.NoError(t, err)
	retryAfter, _ := got.Extra["execute-loop-retry-after"].(string)
	require.NotEmpty(t, retryAfter, "push_failed must park the bead")
	parsed, perr := time.Parse(time.RFC3339, retryAfter)
	require.NoError(t, perr, "execute-loop-retry-after must parse as RFC3339")
	delta := parsed.Sub(startedAt)
	assert.LessOrEqual(t, delta, MaxLoopCooldown+time.Minute,
		"push_failed cooldown must cap at MaxLoopCooldown (24h), got %s", delta)
}

// TestExecuteBeadWorkerPushConflictParksAndEmitsEvent pins AC #3 + #5 of
// ddx-a458af7c: push_conflict (auto-merge during push recovery failed)
// emits a structured `push-conflict` event, parks the bead under the 24h
// cap, and is distinct from generic execution_failed.
func TestExecuteBeadWorkerPushConflictParksAndEmitsEvent(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	conflictDetail := PushConflictReasonPrefix + " auto-recovery retry push: CONFLICT (content)"
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusPushConflict,
				Detail:    conflictDetail,
				SessionID: "sess-pconf",
				BaseRev:   "aaaa1111",
				ResultRev: "cccc3333",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	startedAt := time.Now().UTC()
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, ExecuteBeadStatusPushConflict, result.LastFailureStatus)

	got, err := store.Get(first.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status, "push_conflict must NOT close the bead")
	require.NotNil(t, got.Extra)
	assert.Equal(t, "push_conflict", got.Extra["execute-loop-last-status"])

	// Cooldown capped at 24h.
	retryAfter, _ := got.Extra["execute-loop-retry-after"].(string)
	require.NotEmpty(t, retryAfter)
	parsed, perr := time.Parse(time.RFC3339, retryAfter)
	require.NoError(t, perr)
	delta := parsed.Sub(startedAt)
	assert.LessOrEqual(t, delta, MaxLoopCooldown+time.Minute,
		"push_conflict cooldown must cap at MaxLoopCooldown (24h), got %s", delta)

	// Structured push-conflict event with the conflict context.
	events, err := store.Events(first.ID)
	require.NoError(t, err)
	var sawPushConflict bool
	for _, ev := range events {
		if ev.Kind == "push-conflict" {
			sawPushConflict = true
			assert.Contains(t, ev.Body, conflictDetail,
				"push-conflict event body must record the conflict detail")
			break
		}
	}
	assert.True(t, sawPushConflict,
		"loop must emit a kind:push-conflict event so operators can see the conflict context")
}

